"use client";

import Link from "next/link";
import { cn } from "@/lib/utils";
import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";

export default function Navbar() {
    const [scrolled, setScrolled] = useState(false);

    useEffect(() => {
        const handleScroll = () => setScrolled(window.scrollY > 20);
        window.addEventListener("scroll", handleScroll);
        return () => window.removeEventListener("scroll", handleScroll);
    }, []);

    return (
        <nav
            className={cn(
                "fixed top-0 w-full z-50 transition-all duration-500 px-6 py-4",
                scrolled ? "py-4" : "py-6"
            )}
        >
            <div className={cn(
                "max-w-7xl mx-auto flex justify-between items-center transition-all duration-500 rounded-full px-8",
                scrolled ? "bg-white/70 backdrop-blur-xl border border-zinc-200/50 shadow-lg py-3" : "bg-transparent py-0"
            )}>
                <Link href="/" className="text-2xl font-heading font-black tracking-tighter text-zinc-900 group">
                    VIBI<span className="text-blue-600 group-hover:text-purple-600 transition-colors">SHA.</span>
                </Link>
                <div className="hidden md:flex gap-8 items-center font-body font-bold text-sm uppercase tracking-widest">
                    {["Home", "Blog", "About"].map((item) => (
                        <Link
                            key={item}
                            href={item === "Home" ? "/" : item === "Blog" ? "/blog" : "#about"}
                            className="relative text-zinc-500 hover:text-zinc-900 transition-colors group"
                        >
                            {item}
                            <span className="absolute -bottom-1 left-0 w-0 h-0.5 bg-blue-600 transition-all group-hover:w-full" />
                        </Link>
                    ))}
                    <motion.div whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}>
                        <Link
                            href="/blog"
                            className="bg-zinc-900 text-white px-6 py-2.5 rounded-full hover:bg-zinc-800 transition-all shadow-xl shadow-zinc-200"
                        >
                            Get Started
                        </Link>
                    </motion.div>
                </div>

                {/* Mobile Menu Icon (Placeholder for now) */}
                <div className="md:hidden flex items-center">
                    <div className="w-6 h-0.5 bg-zinc-900 mb-1.5" />
                    <div className="w-6 h-0.5 bg-zinc-900" />
                </div>
            </div>
        </nav>
    );
}
